import React from 'react';
import { Link } from 'react-router-dom';

function Home() {
  return (
    <div className="home-container">
      <header className="py-5 text-center bg-light border-bottom">
        <div className="container">
          <div className="row align-items-center">
            <div className="col-lg-6 text-lg-start">
              <h1 className="display-4 fw-bold">Build Your Dream Project</h1>
              <p className="lead text-muted">I provide high-quality web solutions and creative designs for your business needs.</p>
              <Link to="/services" className="btn btn-primary btn-lg px-5 shadow">View My Services</Link>
            </div>
            <div className="col-lg-6 mt-4 mt-lg-0">
              {/* Image Placeholder - तुम्ही तुमची इमेज इथे टाका */}
              <img 
                src="https://images.unsplash.com" 
                alt="Freelancer Workspace" 
                className="img-fluid rounded shadow-lg"
              />
            </div>
          </div>
        </div>
      </header>
    </div>
  );
}

export default Home;
